#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {int cat; long long time;} Pair;
int cmpPair(const void *a, const void *b){
    Pair *p=(Pair*)a, *q=(Pair*)b;
    if(p->cat!=q->cat) return p->cat - q->cat;
    return (p->time > q->time) - (p->time < q->time);
}
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        int *A = (int*)malloc(N*sizeof(int));
        long long *B = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%d",&A[i]);
        for(int i=0;i<N;i++) scanf("%lld",&B[i]);
        Pair *arr = (Pair*)malloc(N*sizeof(Pair));
        for(int i=0;i<N;i++){arr[i].cat=A[i]; arr[i].time=B[i];}
        qsort(arr,N,sizeof(Pair),cmpPair);
        // compress to minima per category
        long long *mins = (long long*)malloc(N*sizeof(long long));
        int m=0;
        for(int i=0;i<N;){
            int cur=arr[i].cat;
            long long best=arr[i].time;
            while(i<N && arr[i].cat==cur){
                if(arr[i].time<best) best=arr[i].time;
                i++;
            }
            mins[m++]=best;
        }
        if(m<K){
            printf("-1\n");
            free(A);free(B);free(arr);free(mins);
            continue;
        }
        qsort(mins,m,sizeof(long long), (int(*)(const void*,const void*)) (long long a,long long b){return (a>b)-(a<b);} );
        long long sum=0;
        for(int i=0;i<K;i++) sum+=mins[i];
        printf("%lld\n",sum);
        free(A);free(B);free(arr);free(mins);
    }
    return 0;
}

