        }
        if((int)best.size()<K){
            cout<<-1<<"\n";
            continue;
        }
        vector<long long> mins; mins.reserve(best.size());
        for(auto &p:best) mins.push_back(p.second);
        nth_element(mins.begin(), mins.begin()+K, mins.end());
        long long ans=0;
        for(int i=0;i<K;++i) ans+=mins[i];
