import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int K = fs.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) A[i] = fs.nextInt();
            long[] B = new long[N];
            for (int i = 0; i < N; i++) B[i] = fs.nextLong();
            HashMap<Integer, Long> map = new HashMap<>(N * 2);
            for (int i = 0; i < N; i++) {
                int cat = A[i];
                long time = B[i];
                map.merge(cat, time, Math::min);
            }
            if (map.size() < K) {
                sb.append(-1).append('\n');
                continue;
            }
            long[] mins = new long[map.size()];
            int idx = 0;
            for (long v : map.values()) mins[idx++] = v;
            Arrays.sort(mins);
            long sum = 0;
            for (int i = 0; i < K; i++) sum += mins[i];
            sb.append(sum).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException { int c, sign = 1, val = 0; do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign; }
        long nextLong() throws IOException { int c; long sign = 1, val = 0; do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign; }
    }
}

