#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        B = [int(next(it)) for _ in range(N)]
        best = {}
        for cat, t in zip(A, B):
            if cat not in best or t < best[cat]:
                best[cat] = t
        if len(best) < K:
            out_lines.append('-1')
            continue
        mins = sorted(best.values())
        out_lines.append(str(sum(mins[:K])))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

